export class ApiError extends Error{constructor(e,t){super(e),this.name="ApiError",this.status=t}}export class ApiService{constructor(){this.baseHeaders={"Content-Type":"application/json","X-Requested-With":"XMLHttpRequest"}}getCsrfToken(){const e=document.querySelector('meta[name="csrf-token"]');return e?e.getAttribute("content"):null}getHeaders(e={}){const t={...this.baseHeaders,...e},r=this.getCsrfToken();return r&&(t["X-CSRF-TOKEN"]=r),t}async get(e,t={}){return this.request(e,{method:"GET",...t})}async post(e,t=null,r={}){return this.request(e,{method:"POST",body:t?JSON.stringify(t):null,...r})}async put(e,t=null,r={}){return this.request(e,{method:"PUT",body:t?JSON.stringify(t):null,...r})}async delete(e,t={}){return this.request(e,{method:"DELETE",...t})}async request(e,t={}){const r={headers:this.getHeaders(t.headers),...t};try{const t=await fetch(e,r);if(!t.ok){let e=null;const r=t.headers.get("content-type");try{r&&r.includes("application/json")&&(e=await t.json())}catch(e){}if(419===t.status){const r=new ApiError("La tua sessione è scaduta. Ricarica la pagina e riprova.",t.status);throw r.data=e,r}if(403===t.status){const r=new ApiError("Accesso negato. Non hai i permessi necessari.",t.status);throw r.data=e,r}if(401===t.status){const r=new ApiError("Non autenticato. Effettua il login e riprova.",t.status);throw r.data=e,r}if(400===t.status){const r=new ApiError(e?.message||"Errore di validazione",t.status,"VALIDATION_ERROR");throw r.data=e,r}const a=new ApiError(`Errore HTTP ${t.status}`,t.status);throw a.data=e,a}const a=t.headers.get("content-type");return a&&a.includes("application/json")?await t.json():await t.text()}catch(e){throw e instanceof ApiError||Need2Talk.Logger.error("ApiService","API request failed",e),e}}async submitForm(e,t,r={}){const a={method:"POST",body:t,headers:{"X-Requested-With":"XMLHttpRequest",...r.headers},...r};return this.request(e,a)}}export class RegistrationApiService extends ApiService{async checkEmailAvailability(e){try{return{available:(await this.post("/api/validate/email",{email:e})).available,error:null}}catch(e){return Need2Talk.Logger.warn("ApiService","Email availability check failed",e),{available:!0,error:"Unable to verify email availability"}}}async checkNicknameAvailability(e){try{return{available:(await this.post("/api/validate/nickname",{nickname:e})).available,error:null}}catch(e){return Need2Talk.Logger.warn("ApiService","Nickname availability check failed",e),{available:!0,error:"Unable to verify nickname availability"}}}async submitRegistration(e){try{const t=await this.submitForm("/auth/register",e);return{success:t.success||!1,errors:t.errors||{},message:t.message||null,redirect:t.redirect||null}}catch(e){return Need2Talk.Logger.error("ApiService","Registration submission failed",e),{success:!1,errors:{},message:"Errore durante la registrazione. Riprova."}}}}export const registrationApi=new RegistrationApiService;